using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1. Strongly-typed metadata retrieval — GetTypeInfo<T>()
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata : {personInfo.Type.Name}  (kind: {personInfo.Kind})");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized with it : {json}");

// 2. Probe without throwing — TryGetTypeInfo(Type, out ...)
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    var typed = (JsonTypeInfo<Person>)found;
    Person p = JsonSerializer.Deserialize("{\"Name\":\"Grace\",\"Age\":42}", typed)!;
    Console.WriteLine($"TryGet succeeded   : deserialized {p}");
}

// Probe for a type the resolver can't handle (contract-less interface)
// DefaultJsonTypeInfoResolver *can* resolve most concrete types, so to
// demonstrate a "not available" path we use a custom resolver that only
// knows about Person.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

if (limited.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("int metadata found  (unexpected)");
else
    Console.WriteLine("int metadata absent : TryGetTypeInfo returned false — no exception");

Console.WriteLine("Done.");

// --- supporting types ---

public record Person(string Name, int Age);

/// Resolver that only provides metadata for <see cref="Person"/>.
file sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

